{
  "schema": {
    "type": "https://w3c-ccg.github.io/vc-json-schemas/",
    "version": "1.0.0",
    "id": "{{$guid}}",
    "name": "OID4VC Pilot Credential",
    "author": "{{issuer_did}}",
    "authored": "2026-01-01T00:00:00.000Z",
    "schema": {
      "$id": "OID4VC-Pilot-Credential-1.0",
      "$schema": "https://json-schema.org/draft/2019-09/schema",
      "description": "Pilot credential for OID4VC Postman collection testing",
      "type": "object",
      "properties": { "name": { "type": "string" } },
      "required": ["name"],
      "additionalProperties": true
    }
  },
  "tags": ["oid4vc-pilot"],
  "status": "PUBLISHED",
  "oid4vciConfig": {
    "oid4vciEnabled": true,
    "oid4vciFormats": ["ldp_vc", "jwt_vc_json"],
    "display": [{ "name": "OID4VC Pilot Credential", "locale": "en-US" }]
  }
}

{
  "schema": {
    "type": "https://w3c-ccg.github.io/vc-json-schemas/",
    "version": "1.0.0",
    "id": "{{$guid}}",
    "name": "Postman mDL Credential",
    "author": "{{mdoc_issuer_did}}",
    "authored": "2026-01-01T00:00:00.000Z",
    "schema": {
      "$id": "PostmanMdlCredential-1.0",
      "$schema": "https://json-schema.org/draft/2019-09/schema",
      "description": "mso_mdoc test credential for the Postman collection",
      "type": "object",
      "properties": {
        "given_name": {
          "type": "string"
        },
        "family_name": {
          "type": "string"
        }
      },
      "required": [
        "given_name"
      ],
      "additionalProperties": true
    }
  },
  "tags": [
    "postman-mdoc"
  ],
  "status": "PUBLISHED",
  "oid4vciConfig": {
    "oid4vciEnabled": true,
    "oid4vciFormats": [
      "mso_mdoc"
    ],
    "display": [
      {
        "name": "Postman mDL Credential",
        "locale": "en-US"
      }
    ],
    "mdoc": {
      "docType": "org.iso.18013.5.1.mDL",
      "namespace": "org.iso.18013.5.1"
    }
  }
}

{
  "schema": {
    "type": "https://w3c-ccg.github.io/vc-json-schemas/",
    "version": "1.0.0",
    "id": "{{$guid}}",
    "name": "Postman Render Method Credential",
    "author": "{{issuer_did}}",
    "authored": "2026-01-01T00:00:00.000Z",
    "schema": {
      "$id": "PostmanRenderMethodCredential-1.0",
      "$schema": "https://json-schema.org/draft/2019-09/schema",
      "description": "W3C VC Render Method test credential",
      "type": "object",
      "properties": {
        "name": {
          "type": "string"
        }
      },
      "required": [
        "name"
      ],
      "additionalProperties": true
    }
  },
  "tags": [
    "postman-render"
  ],
  "status": "PUBLISHED",
  "oid4vciConfig": {
    "oid4vciEnabled": true,
    "oid4vciFormats": [
      "jwt_vc_json"
    ],
    "display": [
      {
        "name": "Postman Render Method Credential",
        "locale": "en-US"
      }
    ],
    "renderMethod": {
      "type": "SvgRenderingTemplate",
      "name": "Postman Card",
      "svg": "<svg xmlns='http://www.w3.org/2000/svg' width='300' height='150'><text x='10' y='50'>{{credentialSubject.name}}</text></svg>"
    }
  }
}

{
  "schema": {
    "type": "https://w3c-ccg.github.io/vc-json-schemas/",
    "version": "1.0.0",
    "id": "{{$guid}}",
    "name": "Postman SD-JWT Credential",
    "author": "{{issuer_did}}",
    "authored": "2026-01-01T00:00:00.000Z",
    "schema": {
      "$id": "PostmanSdJwtCredential-1.0",
      "$schema": "https://json-schema.org/draft/2019-09/schema",
      "description": "vc+sd-jwt test credential",
      "type": "object",
      "properties": {
        "name": {
          "type": "string"
        },
        "age_over_18": {
          "type": "boolean"
        }
      },
      "required": [
        "name"
      ],
      "additionalProperties": true
    }
  },
  "tags": [
    "postman-sdjwt"
  ],
  "status": "PUBLISHED",
  "oid4vciConfig": {
    "oid4vciEnabled": true,
    "oid4vciFormats": [
      "vc+sd-jwt"
    ],
    "vct": "Postman SD-JWT Credential",
    "display": [
      {
        "name": "Postman SD-JWT Credential",
        "locale": "en-US"
      }
    ]
  }
}
